import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Services from './components/Services';
import BillingForm from './components/BillingForm';
import SavedBills from './components/SavedBills';
import InvoicePreview from './components/InvoicePreview';
import { Phone, MapPin } from 'lucide-react';

function App() {
  const [activeTab, setActiveTab] = useState('home'); // 'home', 'billing', 'history', 'preview'
  const [savedInvoices, setSavedInvoices] = useState([]);
  const [selectedInvoice, setSelectedInvoice] = useState(null);

  useEffect(() => {
    const stored = localStorage.getItem('electrician_invoices');
    if (stored) {
      setSavedInvoices(JSON.parse(stored));
    }
  }, []);

  const saveInvoice = (invoice) => {
    const updated = [invoice, ...savedInvoices];
    setSavedInvoices(updated);
    localStorage.setItem('electrician_invoices', JSON.stringify(updated));
    setSelectedInvoice(invoice);
    setActiveTab('preview');
  };

  const viewInvoice = (invoice) => {
    setSelectedInvoice(invoice);
    setActiveTab('preview');
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-grow container mx-auto px-4 py-8">
        {activeTab === 'home' && (
          <>
            <Hero setActiveTab={setActiveTab} />
            <Services />
            <section className="mt-16 glass p-8 rounded-2xl text-center">
              <h2 className="text-3xl font-bold mb-4 gold-text-gradient">24/7 Emergency Service Available</h2>
              <p className="text-gray-400 mb-6">Need an electrician urgently? We are just a call away.</p>
              <div className="flex flex-wrap justify-center gap-4">
                <a href="tel:7498045041" className="bg-yellow-500 hover:bg-yellow-600 text-black font-bold py-3 px-8 rounded-full transition-all flex items-center gap-2">
                  <Phone size={20} /> Call Now
                </a>
                <a href="https://wa.me/917498045041" target="_blank" rel="noreferrer" className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-8 rounded-full transition-all flex items-center gap-2">
                  WhatsApp Now
                </a>
              </div>
            </section>
          </>
        )}

        {activeTab === 'billing' && (
          <BillingForm onSave={saveInvoice} />
        )}

        {activeTab === 'history' && (
          <SavedBills invoices={savedInvoices} onView={viewInvoice} />
        )}

        {activeTab === 'preview' && selectedInvoice && (
          <div className="max-w-4xl mx-auto">
             <button
              onClick={() => setActiveTab('history')}
              className="mb-4 text-yellow-500 hover:underline flex items-center gap-2 no-print"
            >
              ← Back to History
            </button>
            <InvoicePreview invoice={selectedInvoice} />
          </div>
        )}
      </main>

      <footer className="mt-auto py-8 border-t border-gray-800 bg-black/50 no-print">
        <div className="container mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-8 text-center md:text-left">
          <div>
            <h3 className="text-xl font-bold text-yellow-500 mb-4">Sohail Mulani</h3>
            <p className="text-gray-400">Professional electrical services for home and business.</p>
          </div>
          <div>
            <h4 className="font-bold mb-4">Contact Info</h4>
            <ul className="text-gray-400 space-y-2">
              <li className="flex items-center justify-center md:justify-start gap-2">
                <Phone size={16} className="text-yellow-500" /> 7498045041
              </li>
              <li className="flex items-center justify-center md:justify-start gap-2">
                <MapPin size={16} className="text-yellow-500" /> Nashik, Maharashtra
              </li>
            </ul>
          </div>
          <div>
            <h4 className="font-bold mb-4">Working Hours</h4>
            <p className="text-gray-400">Monday - Sunday: 24/7 Service Available</p>
          </div>
        </div>
        <div className="text-center mt-8 text-gray-600 text-sm">
          © {new Date().getFullYear()} Sohail Mulani Electrician. All rights reserved.
        </div>
      </footer>
    </div>
  );
}

export default App;
